from transformers import AutoModelForMaskedLM, AutoTokenizer
from elasticsearch import Elasticsearch
import json

# Load model and tokenizer for masked language modeling
model = AutoModelForMaskedLM.from_pretrained("bert-base-cased")
tokenizer = AutoTokenizer.from_pretrained("bert-base-cased")

# Initialize Elasticsearch client with appropriate settings
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def vectorize_documents(docs):
    vectorized_docs = []

    for doc in docs:
        encoding = tokenizer.encode_plus(doc, add_special_tokens=True, return_tensors='tf')
        input_ids = encoding['input_ids'].numpy()
        masked_token_indices = [index for index, token in enumerate(tokenizer.convert_ids_to_tokens(input_ids)) if token == "[MASK]"]
        masked_token_ids = [input_ids[i] for i in masked_token_indices]

        with open('temp_docs/doc{}.txt'.format(doc), 'w') as f:
            f.write(doc)

        vector = model(input_ids, labels=masked_token_ids).logits[0][masked_token_indices[0]]
        vectorized_docs.append({'id': doc, 'vector': vector})
    return vectorized_docs

def save_to_es(vectorized_docs):
    for vec_doc in vectorized_docs:
        es.index(index='company-knowledge-base', id=vec_doc['id'], body=vec_doc)

